`ifndef VERILATOR
module testbench;
  reg [4095:0] vcdfile;
  reg clock;
`else
module testbench(input clock, output reg genclock);
  initial genclock = 1;
`endif
  reg genclock = 1;
  reg [31:0] cycle = 0;
  vector_unit_formal UUT (

  );
`ifndef VERILATOR
  initial begin
    if ($value$plusargs("vcd=%s", vcdfile)) begin
      $dumpfile(vcdfile);
      $dumpvars(0, testbench);
    end
    #5 clock = 0;
    while (genclock) begin
      #5 clock = 0;
      #5 clock = 1;
    end
  end
`endif
  initial begin
`ifndef VERILATOR
    #1;
`endif
    // UUT.$auto$async2sync.\cc:107:execute$4699  = 1'b0;
    // UUT.$auto$async2sync.\cc:116:execute$4697  = 1'b1;
    // UUT.$auto$async2sync.\cc:116:execute$4703  = 1'b1;
    // UUT.$auto$async2sync.\cc:116:execute$4709  = 1'b1;
    // UUT.$past$vector_unit_formal.\sv:28$4$0  = 1'b0;
    // UUT.dut.$auto$async2sync.\cc:253:execute$4619  = 8'b00000000;
    // UUT.dut.$auto$async2sync.\cc:253:execute$4621  = 5'b00000;
    // UUT.dut.$auto$async2sync.\cc:253:execute$4623  = 5'b00000;
    // UUT.dut.$auto$async2sync.\cc:253:execute$4625  = 5'b00000;
