    // UUT.dut.$auto$async2sync.\cc:253:execute$4635  = 1'b0;
    // UUT.dut.$auto$async2sync.\cc:253:execute$4637  = 1'b0;
    UUT.dut.sram_addr_reg = 20'b00000000000000000000;
    UUT.dut.sram_wdata_reg = 1024';
    UUT.dut.\vrf[0]  = 1024';
    UUT.dut.\vrf[10]  = 1024';
    UUT.dut.\vrf[11]  = 1024';
    UUT.dut.\vrf[12]  = 1024';
    UUT.dut.\vrf[13]  = 1024';
    UUT.dut.\vrf[14]  = 1024';
    UUT.dut.\vrf[15]  = 1024';
