    UUT.dut.\vrf[22]  = 1024';
    UUT.dut.\vrf[23]  = 1024';
    UUT.dut.\vrf[24]  = 1024';
    UUT.dut.\vrf[25]  = 1024';
    UUT.dut.\vrf[26]  = 1024';
    UUT.dut.\vrf[27]  = 1024';
    UUT.dut.\vrf[28]  = 1024';
    UUT.dut.\vrf[29]  = 1024';
    UUT.dut.\vrf[2]  = 1024';
